<script setup lang="ts">
import { computed, onBeforeUnmount, ref, watch } from "vue";
import type { RepairCategory, RepairPlan, RepairScope } from "../types";
import { categoryLabels, repairRules, rulesForCategory } from "../repair/registry";
import { useDocumentStore } from "../stores/document";

const props = defineProps<{ store: ReturnType<typeof useDocumentStore> }>();
const emit = defineEmits<{ status: [message: string]; "show-diff": [] }>();
const tab = ref<"manual" | "auto" | "settings">("manual"); const manualKind = ref<"rule" | "category">("rule"); const manualRuleId = ref("formula-trim"); const manualCategory = ref<RepairCategory>("formula"); const manualScope = ref<RepairScope>("document"); const manualPlan = ref<RepairPlan>(); const autoPlan = ref<RepairPlan>(); const selectedAutoIds = ref<string[]>([]); let timer: number | undefined;
const categories = Object.keys(categoryLabels) as RepairCategory[]; const hasSelection = computed(() => props.store.selection.from !== props.store.selection.to);
const candidateGroups = computed(() => categories.map(category => ({ category, candidates: autoPlan.value?.candidates.filter(candidate => candidate.category === category) ?? [] })).filter(group => group.candidates.length));
function generateManual() { if (manualScope.value === "selection" && !hasSelection.value) return; const target = manualKind.value === "rule" ? { kind: "rule" as const, id: manualRuleId.value } : { kind: "category" as const, id: manualCategory.value }; manualPlan.value = props.store.buildRepairPlan(manualScope.value, target); emit("show-diff"); emit("status", `已生成手动修复预览：${manualPlan.value.candidates.length} 项`); }
function refreshAuto() { autoPlan.value = props.store.buildRepairPlan("document", { kind: "automatic" }); selectedAutoIds.value = autoPlan.value.candidates.map(candidate => candidate.id); }
function applyManual() { if (!manualPlan.value) return; try { props.store.applyRepairPlan(manualPlan.value, manualPlan.value.candidates.map(candidate => candidate.id), "手动修复"); emit("status", "已应用手动修复，可一次撤销"); manualPlan.value = undefined; refreshAuto(); } catch (error) { emit("status", error instanceof Error ? error.message : "修复计划无法应用"); } }
function applyAuto() { if (!autoPlan.value) return; try { props.store.applyRepairPlan(autoPlan.value, selectedAutoIds.value, "自动修复：应用已选项目"); emit("status", "已应用自动修复预览中的选中项目，可一次撤销"); refreshAuto(); } catch (error) { emit("status", error instanceof Error ? error.message : "修复计划无法应用"); } }
function toggleAuto(ids: string[], checked: boolean) { const next = new Set(selectedAutoIds.value); ids.forEach(id => checked ? next.add(id) : next.delete(id)); selectedAutoIds.value = [...next]; }
function setEnabled(id: string, checked: boolean) { const next = new Set(props.store.repairSettings.enabledRuleIds); checked ? next.add(id) : next.delete(id); props.store.updateRepairSettings({ ...props.store.repairSettings, enabledRuleIds: [...next] }); refreshAuto(); }
function setConfidence(value: number) { props.store.updateRepairSettings({ ...props.store.repairSettings, minimumConfidence: Math.max(0, Math.min(1, value)) }); refreshAuto(); }
watch(() => props.store.text, () => { window.clearTimeout(timer); timer = window.setTimeout(refreshAuto, 600); }, { immediate: true }); onBeforeUnmount(() => window.clearTimeout(timer));
function openAutomatic() { tab.value = "auto"; refreshAuto(); }
defineExpose({ openAutomatic });
</script>
<template>
  <div class="repair">
    <nav class="repair-tabs"><button :class="{ active: tab === 'manual' }" @click="tab = 'manual'">手动修复</button><button :class="{ active: tab === 'auto' }" @click="tab = 'auto'; refreshAuto()">自动预览</button><button :class="{ active: tab === 'settings' }" @click="tab = 'settings'">设置</button></nav>
    <section v-if="tab === 'manual'" class="content"><p class="eyebrow">一次选择一个目标</p><label><input v-model="manualKind" type="radio" value="rule"> 具体规则</label><select v-if="manualKind === 'rule'" v-model="manualRuleId"><option v-for="rule in repairRules" :key="rule.id" :value="rule.id">{{ rule.label }}</option></select><label><input v-model="manualKind" type="radio" value="category"> 规则大类</label><select v-if="manualKind === 'category'" v-model="manualCategory"><option v-for="category in categories" :key="category" :value="category">{{ categoryLabels[category] }}（{{ rulesForCategory(category).filter(rule => store.repairSettings.enabledRuleIds.includes(rule.id)).length }} 项已启用）</option></select><p class="eyebrow">修复范围</p><label><input v-model="manualScope" type="radio" value="document"> 全文</label><label :class="{ disabled: !hasSelection }"><input v-model="manualScope" type="radio" value="selection" :disabled="!hasSelection"> 当前选区</label><button class="primary" @click="generateManual">生成预览</button><div v-if="manualPlan" class="plan"><strong>{{ manualPlan.candidates.length }} 项可应用修复</strong><p v-for="note in manualPlan.skipped" :key="note" class="warning">{{ note }}</p><p v-for="note in manualPlan.conflicts" :key="note" class="warning">{{ note }}</p><div v-for="item in manualPlan.candidates" :key="item.id" class="candidate"><small>{{ categoryLabels[item.category] }} · {{ item.label }}</small><code>{{ item.originalText }} → {{ item.replacement }}</code></div><button class="primary" :disabled="!manualPlan.candidates.length" @click="applyManual">应用此计划</button></div></section>
    <section v-else-if="tab === 'auto'" class="content"><div class="row"><p class="eyebrow">自动修复预览</p><button @click="refreshAuto">刷新</button></div><p class="hint">检测不会修改正文；仅在点击“一键修复”后应用。</p><div v-for="group in candidateGroups" :key="group.category" class="group"><label><input type="checkbox" :checked="group.candidates.every(item => selectedAutoIds.includes(item.id))" @change="toggleAuto(group.candidates.map(item => item.id), ($event.target as HTMLInputElement).checked)"> <strong>{{ categoryLabels[group.category] }}</strong> <small>{{ group.candidates.length }}</small></label><div v-for="rule in repairRules.filter(rule => rule.category === group.category)" :key="rule.id" class="rule"><template v-if="group.candidates.filter(item => item.ruleId === rule.id).length"><label><input type="checkbox" :checked="group.candidates.filter(item => item.ruleId === rule.id).every(item => selectedAutoIds.includes(item.id))" @change="toggleAuto(group.candidates.filter(item => item.ruleId === rule.id).map(item => item.id), ($event.target as HTMLInputElement).checked)"> {{ rule.label }}</label><label v-for="item in group.candidates.filter(item => item.ruleId === rule.id)" :key="item.id" class="candidate"><input v-model="selectedAutoIds" type="checkbox" :value="item.id"><code>{{ item.originalText }} → {{ item.replacement }}</code></label></template></div></div><p v-if="!autoPlan?.candidates.length" class="empty">没有可自动应用的安全修复</p><button class="primary" :disabled="!selectedAutoIds.length" @click="applyAuto">一键修复选中项（{{ selectedAutoIds.length }}）</button></section>
    <section v-else class="content"><p class="eyebrow">参与类别修复与自动预览的规则</p><label v-for="rule in repairRules" :key="rule.id" class="setting"><input type="checkbox" :checked="store.repairSettings.enabledRuleIds.includes(rule.id)" @change="setEnabled(rule.id, ($event.target as HTMLInputElement).checked)"><span>{{ categoryLabels[rule.category] }} · {{ rule.label }}</span></label><label class="setting">自动修复最低置信度 <input type="number" min="0" max="1" step="0.1" :value="store.repairSettings.minimumConfidence" @change="setConfidence(Number(($event.target as HTMLInputElement).value))"></label></section>
  </div>
</template>
<style scoped>
.repair { font-size: 12px; }.repair-tabs { height: auto; padding: 0; margin: 0 -10px 12px; }.content { display: grid; gap: 9px; }.content select, .content input[type="number"] { width: 100%; background: #10191c; color: #d8e5e1; border: 1px solid #315052; padding: 6px; }.content label { color: #b9cac5; }.primary { border: 1px solid #e6a845; background: #e6a845; color: #17201d; padding: 7px; font-weight: 700; }.plan, .group { border: 1px solid #294347; padding: 9px; display: grid; gap: 7px; }.candidate { display: grid; gap: 3px; padding: 5px; border-left: 2px solid #315052; }.candidate code { white-space: pre-wrap; color: #9db5ae; font: 11px/1.4 "Cascadia Code", monospace; }.rule { margin-left: 10px; display: grid; gap: 4px; }.warning { color: #f1b75b; margin: 0; }.hint { color: #78908c; margin: 0; }.row { display: flex; justify-content: space-between; align-items: center; }.row .eyebrow { margin: 0; }.setting { display: flex; gap: 6px; align-items: center; }.disabled { opacity: .45; }.empty { color: #78908c; }.repair button { border: 1px solid #315052; background: transparent; color: inherit; border-radius: 3px; padding: 5px 7px; }.repair button.primary { background: #e6a845; color: #17201d; border-color: #e6a845; }
</style>
